var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이거 놔! 내가 누군지 알고 내 몸에 손을 대!!","JPN":"放しなさい！　私を誰だと思ってるの！！","ENG":"Let go of me! How dare you touch me! Do you even know who I am?!","TWN":"放開我！你們知道我是誰嗎？竟敢用你們的髒手碰我！！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"네놈들 얼굴 전부 기억해 뒀어! 날 이 따위로 대접한 거 후회하게 만들어 줄 거야!","JPN":"あなたたちの顔、全部覚えておいたわ！　私をこんな風に扱ったこと後悔させてやる！","ENG":"I'll remember all of your ugly faces! You're going to regret this!","TWN":"你們的臉我全都記下了！我會讓你們後悔這樣對我的！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"당장 이 문 열어! 안 열어?!","JPN":"今すぐにこの扉を開けなさい！　早く！！","ENG":"Open this door immediately! I demand that you open! This! Door!","TWN":"立刻把門打開！還不給我開門？！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRISON_NPC_NULL_NULL","text":{"KOREA":"그건 안 됩니다. 의장님의 지시라서요.","JPN":"それはいけません。議長のご指示ですので。","ENG":"No can do. It's an order from the Chairman himself.","TWN":"恕難從命，這是議長的指示。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRISON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"의장님?","JPN":"議長？","ENG":"The Chairman?","TWN":"議長？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"당신, 평의회 사람이었어요? 어휴, 난 그런 줄도 모르고.","JPN":"あなた、評議会の人だったんですか？　まあ、私ったらそんなことも知らないで。","ENG":"Y-you're a member of the Council? Well, why didn't you say so?","TWN":"你是評議會的人嗎？哎呀，是我有眼不識泰山。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRISON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"탈옥 사건 얘기는 들었어요. 언제 나갈 수 있는 거죠?","JPN":"脱獄事件の話は聞きました。いつ出られるのかしら。","ENG":"I heard about the jailbreak. So? When will I be released?","TWN":"我有聽說過逃獄事件，那我什麼時候才能出去？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRISON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PRISON_NPC_NULL_NULL","text":{"KOREA":"하하, 너무 서두르지 마세요. 감옥 공기를 쐬니 정신이 돌아오셨잖습니까.","JPN":"はは、あまり焦らないでください。牢獄の空気に当たって、正気を取り戻したではありませんか。","ENG":"Haha, what's the hurry? After a whiff of the prison air, you came back to your sense, didn't you?","TWN":"哈哈，別心急，你不是呼吸到監獄的空氣後，精神才恢復正常的嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRISON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이런 불결한 환경에 언제까지 있을 수는 없잖아요.","JPN":"いつまでもこんな不潔なところにいられるわけないじゃないですか。","ENG":"Well, I can't be held up in this filthy place forever, can I?","TWN":"總不能一直待在這種骯髒的環境嘛。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRISON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"들어 봐요. 전 맨손으로 헤이븐 랜드를 세웠어요. 그 사람만 좋은 짐덩이들을 데리고!","JPN":"聞いてください。私は何もないところからヘイブンランドを作ったんです。あの性格だけはいいお荷物たちを連れて！","ENG":"Listen. I built Havenland from the ground up all by myself. And I had to do it while carrying around those dead weight people-loving idiots!","TWN":"你聽我說，是我帶著那些空有一副好心腸的傢伙，一手將天堂樂園建立起來的。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"당신도 헤이븐의 이름은 들었죠? 제 두뇌는 의장님께 아주 큰 힘이 될 거예요.","JPN":"あなたもヘイブンの名前は聞いてるでしょう？　私の頭脳はきっと議長のお役に立つと思います。","ENG":"You've heard of the name Haven, haven't you? My genius will undoubtedly be of great benefit to the Chairman.","TWN":"你也聽過天堂這號人物吧？我的聰明才智對議長會很有幫助的。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"아, 거 쫑알쫑알 되게 시끄럽네.","JPN":"ああ、もうぶつぶつうるさいなあ。","ENG":"Ugh, will you quit yapping already?","TWN":"喂，嘰嘰喳喳地吵什麼啦！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"……응? 누, 누구야?","JPN":"……うん？　だ、誰？","ENG":"...Huh? W-who're you?","TWN":"……嗯？你…你是誰？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"야, 저 여자 진짜 모르는 눈치다.","JPN":"おい、あの女、本当に知らないみたいだね。","ENG":"Hey, I don't think she knows.","TWN":"喂，那女的真的是目中無人欸！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"그러게. 되게 서운하네. <color=#ffd34c>우린</color> 언제 오나 계속 기다렸는데.","JPN":"ほんと。悲しいなあ。<color=#ffd34c>私たち</color>はいつ来るかずっと待ってたのに。","ENG":"Yeah. What a shame. <color=#ffd34c>We</color> have been anxiously waiting for you.","TWN":"對啊，真傷心。<color=#ffd34c>我們</color>可是等她進來等很久咧。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"뭐?! 너희들, 날 알아……?","JPN":"え！？　あなたたち、私のことを知ってるのかしら……？","ENG":"What?! Do you know who I am...?","TWN":"什麼？！你們，認識我……？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"당연하지, 헤론.","JPN":"当たり前でしょ、ヘロン。","ENG":"Of course we know you, Heron.","TWN":"當然囉，海倫。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"뭐 하는 것들이야! 감히 내 이름을 함부로 부르다니!","JPN":"何者なの！　私の名前を呼ぶなんて！","ENG":"What do you think you are doing?! How dare you say my name?!","TWN":"你們是誰！竟敢直呼我的名諱！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"아, 까맣게 잊었나 보네. 혹시나 기억하면 어쩌나 했어.","JPN":"あ、完全に忘れてるみたいだね。もしかして覚えてたらどうしようと思った。","ENG":"Wow. I think she completely forgot about us. For a second there I thought she'd remember.","TWN":"看來你不記得啦，我還擔心你記得的話怎麼辦呢。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"뭘 바라겠어. 그 헤론인데.","JPN":"何を期待してるんだよ。あのヘロンじゃん。","ENG":"What did you expect? It's Heron after all.","TWN":"　　　"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"가, 가까이 오지 마!","JPN":"ち、近づかないで！","ENG":"D-don't come near me!","TWN":"別…別過來！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이봐요! 이 연놈들은 다 뭐예요?! 구경만 하지 말고 어서 꺼내 줘요!","JPN":"ちょっと！　こいつらはいったい何なのですか？！　見てばかりいないで、早く出して！","ENG":"Guard! What's the meaning of this?! Don't just stand there and get me out of here!","TWN":"喂！你們這群看門狗在做什麼？！看戲嗎！還不快解開我！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRISON_NPC_NULL_NULL","text":{"KOREA":"하하. 너무 걱정 마세요. 다 위저드 출신들입니다.","JPN":"はは。あまり心配しないでください。みんなウィザードの出身です。","ENG":"Ha ha! Don't worry. They're all Wizard kids.","TWN":"哈哈，別擔心，大家全都是從巫師出來的。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRISON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"위저드……?","JPN":"ウィザード……？","ENG":"Wizard...?","TWN":"巫師……？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRISON_NPC_NULL_NULL","text":{"KOREA":"네. 밀거래, 장기매매, 그 외 여러 범죄로 붙잡혀 왔습니다.","JPN":"はい。密売、臓器売買、その他諸々の犯罪で捕まったんです。","ENG":"Yes. They're here on counts of smuggling, organ trafficking, and a slew of other crimes.","TWN":"對，因為走私、器官販賣等等罪名被抓進來的。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRISON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"아…… 아아…….","JPN":"あ……ああ……","ENG":"Oh... N-no...","TWN":"呃……喔……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PRISON_NPC_NULL_NULL","text":{"KOREA":"의장님의 전언입니다.","JPN":"議長からの伝言です。","ENG":"There's also a message from the Chairman.","TWN":"這是議長要我轉告你的。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRISON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PRISON_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>저에겐 당신이 필요없습니다. 아이들과 사이 좋게 지내세요</color>.","JPN":"<color=#ffd34c>私にあなたは必要ありません。子どもたちと仲良くしてください</color>。","ENG":"<color=#ffd34c>I have no use for you. Please get along well with the children.</color>","TWN":"<color=#ffd34c>我已經不再需要你，和孩子們好好相處吧。</color>"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRISON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"아니야, 이건 아니지. 그럴 리가요. 전부 시험이죠? 그런 거죠?","JPN":"違う、これはないわ。そんな。全部試験でしょう？　そうなんでしょう？","ENG":"No. Th-that can't be...! This is all just a test, right? It's a test!","TWN":"不，不會的，怎麼可能！這只是在考驗我吧？對吧？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"흐흥~ 흐으응~♪","JPN":"ふふん～ふううん～♪","ENG":"Hmm hm h-hmm♪","TWN":"哼哼～哼哼哼～♪"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"기억나? 네가 우리 머리맡에서 들려 주던 노래야.","JPN":"覚えてる？　あんたが私たちの枕もとで聞かせてくれた歌だよ。","ENG":"Do you remember this song? You used to sing it to us when we went to bed.","TWN":"記得嗎？這是你在我們床邊哼的歌。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"아직도 머릿속에서 들려온다니까. 악몽처럼 끈질기게 들러붙어서 안 떨어지더라.","JPN":"まだ頭の中から聞こえてくるんだよ。悪夢のようにしつこくくっついて離れないんだよね。","ENG":"Can you believe it's still stuck inside my head? It's like a nightmare that won't leave me alone.","TWN":"我腦袋裡都還常常想起這首歌呢，就像惡夢一樣揮之不去！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"아…… 아아아아아아아……!","JPN":"あ……あああああああ……！","ENG":"Ah... AAAAAAH...!","TWN":"啊……啊啊啊啊啊啊……！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"흐흥~ 흐으응~♪","JPN":"ふふん～ふううん～♪","ENG":"Hmm hm h-hmm♪","TWN":"哼哼～哼哼哼～♪"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"고생문이 열렸군. 오래 버텨야 할 텐데.","JPN":"苦労が始まったな。耐えられるといいんだが。","ENG":"Looks like tough times are headed your way. I hope you make it out in one piece.","TWN":"受苦之路已經開啟，要撐一陣子呢。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"무슨 얘기야?","JPN":"なんの話？","ENG":"What's that supposed to mean?","TWN":"什麼意思？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"아무것도 아니야.","JPN":"何でもないさ。","ENG":"Nothing.","TWN":"沒什麼。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그나저나 헤이븐, 계속 감옥에 있으면 지루하지 않겠나?","JPN":"それよりヘイブン、ずっと牢獄にいると暇ではないかい？","ENG":"By the way, Haven. Won't you be bored being stuck in prison for so long?","TWN":"不過天堂，一直待在監獄裡不會無聊嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"원한다면 내보내 줄 수 있어. 이번엔 시간이 많이 필요하겠지만.","JPN":"望むなら出してやることもできる。今度は結構時間が必要になるだろうが。","ENG":"If you want, I can get you out. But it'll take me some time to get things in order.","TWN":"你想要的話，我可以放你出去，只是這次會需要比較多時間。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"그건 됐어. 내 죗값은 내가 치를 테니까.","JPN":"いいんだ。自分で罪滅ぼしをするから。","ENG":"No thanks. I'm here to pay for what I've done.","TWN":"不用，既然犯法就該付出代價。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"자네 생각이 그렇다면야. 그 대신에 유능한 변호사를 추천해 주지.","JPN":"君がそうしたいなら。その代わりに、有能な弁護士を推薦しよう。","ENG":"If you say so. Then I'll recommend a good lawyer for you instead.","TWN":"既然你心意已決，那還是我替你找個厲害的律師吧？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"그래. 다음부터는 정식으로 면회 절차를 밟아서 와 줘.","JPN":"うん。今度からは正式に面会の手続きをしてから来て。","ENG":"Sure. Oh, and next time, please go through the official visitation process if you want to talk with me.","TWN":"好，下次來找我時麻煩走正規的會面流程。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"하하, 그러지. 시원시원하니 좋군.","JPN":"はは、そうしょう。さっぱりしてていいな。","ENG":"Haha. Will do. I like a cool person like you.","TWN":"哈哈，沒問題，說話不拐彎抹角，很好。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"이만 가 보겠네. 아버지의 부족한 한 걸음을 채워 드려야 하거든.","JPN":"もう失礼しよう。我が父の足りない一歩を満たして差し上げないといけないんでね。","ENG":"I'll get going then. I need to nudge Father to take that one extra step.","TWN":"那我先告辭，我還得去補足爸爸缺少的那一步呢。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"아. 잠깐.","JPN":"あ。待って。","ENG":"Oh, wait.","TWN":"先等一下。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"헤이븐 랜드가 추락하기 전날 밤에…… 혹시 무슨 일 있었어?","JPN":"ヘイブンランドが墜落する前の夜に……もしかして何かあった？","ENG":"The night before Havenland crashed... Did something happen?","TWN":"天堂樂園迫降的前一晚……有發生什麼事嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"자네가 술을 거나하게 마시고 이래저래 푸념을 늘어놨지.","JPN":"だいぶ酒に酔っていた君は、あれこれ愚痴をこぼしたんだ。","ENG":"You drank your sorrows away and complained about something to me.","TWN":"你喝得爛醉，在那發牢騷。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"자네 누이와, 자네 자신의 부담감에 대해서.","JPN":"君の姉と、君自分の負担についてね。","ENG":"About your sister, the pressure you feel, and so on.","TWN":"內容是有關你和你姊姊的壓力。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"나는 그런 자네에게 충고를 한마디 해 줬을 뿐이야.","JPN":"私はそういう君に一言忠告をしてあげたまでだ。","ENG":"And all I did was give you a piece of advice.","TWN":"然後我就給你一句忠告，如此而已。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"가면을 벗어 보라고, 말이지.","JPN":"仮面を脱いでみろ、とな。","ENG":"To take off, my mask.","TWN":"你叫我脫下面具對吧？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"첨언하자면 나는 아무 곳에나 발을 밀어 넣는 성격이 아니야. 우연이란 섬세하거든.","JPN":"言っておくが、私はどこにでも足を踏み入れる性格ではない。偶然というものはデリケートなんだ。","ENG":"I should also tell you that I am not one who goes around intervening in other people’s lives. Coincidence is a delicate balance, you see...","TWN":"真要說的話，我不是那種雞婆的個性，所謂的巧合就是這麼回事。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그러니 이번 일은 나와 아무런 관련이 없다네. ","JPN":"だから今度のことは私と何の関係もない。 ","ENG":"As such, what happened has nothing to do with me. ","TWN":"所以這次的事件完全與我無關。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"널 아는 사람 중에 누가 그 말을 믿겠어? 다들 네가 배후에서 꾸몄다고 생각할걸.","JPN":"君を知る人の中で、その言葉を信じる人はいないだろうね。みんな、君が背後にいると思うはずだ。","ENG":"You think anyone who knows you will really believe that? They'll all think you were behind it.","TWN":"認識你的人當中，誰會相信與你無關？大家都會猜你就是幕後的指使者吧？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"타당한 의심이네만, 이렇게 답해 주지.","JPN":"妥当な疑いだが、こう答えるとしよう。","ENG":"A reasonable suspicion, but allow me to respond.","TWN":"這是合理的懷疑，我這麼回答吧。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"아버지는 그럴지 몰라도 나는 아니야. 동화를 현실의 잣대로 파악하지 말게.","JPN":"我が父はそうかもしれないが、私は違う。現実の基準でおとぎ話を判断しないでほしい。","ENG":"Perhaps Father would interject, but not me. You shouldn't view a fairy tale through the lens of reality.","TWN":"爸爸或許是，但我不是，不要拿童話來衡量現實。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"<color=#ffd34c>그리고 오래오래 행복하게 살았습니다</color>에 설명이 필요한가?","JPN":"<color=#ffd34c>そしてみんないつまでも幸せに暮らしましたとさ</color>に説明が必要か？","ENG":"Do you need an explanation for <color=#ffd34c>\\"and they lived happily ever after\\"</color>?","TWN":"<color=#ffd34c>永遠幸福快樂，</color>還有需要解釋嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"……그것도 그렇네.","JPN":"……それもそうだね。","ENG":"...I guess you're right about that.","TWN":"……說的也沒錯。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그렇지. 주어진 행운에 감사하게.","JPN":"そのとおり。与えられた幸運に感謝することだ。","ENG":"Yes. Be grateful for the good luck that has come your way.","TWN":"對吧，對得到的幸運要心懷感激。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"자네는 지금보다 더 성장할 수 있어. 그 날이 오길 기대하고 있겠네.","JPN":"君は今よりもっと成長できる。その日が来ることを楽しみにしてるぞ。","ENG":"You have the potential to become much greater than you are right now. I'll be waiting patiently until then.","TWN":"你會比現在更加成熟，我會等候那天到來的。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그럼 다음에 다시 보세나, 헤이븐.","JPN":"それではまた会おう、ヘイブン。","ENG":"Well, then. I'll see you again sometime, Haven.","TWN":"那就下次見囉，天堂。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};